import env from './env.js'
import {
	getToken
} from './auth.js'

/**
 * WebSocketзұ»е°ҒиЈ…пјҲuni-appзүҲпјү
 * з”ЁдәҺеңЁchat.vueдёӯе®һзҺ°е®һж—¶иҒҠеӨ©еҠҹиғҪ
 */
class WebSocketClient {
	constructor(url = '', options = {}, userId = '') {
		// й»ҳи®ӨWebSocket URL
		this.url = url || this.getWebSocketUrl(userId)
		this.options = options
		this.socketTask = null
		this.isConnected = false
		this.isConnecting = false // ж·»еҠ иҝһжҺҘдёӯзҠ¶жҖҒ
		this.reconnectTimer = null
		this.reconnectAttempts = 0
		this.maxReconnectAttempts = options.maxReconnectAttempts || 5
		this.reconnectInterval = options.reconnectInterval || 3000
		this.messageQueue = []
		this.socketId = null
		this.userId = userId
		this.isManualClose = false // ж·»еҠ жүӢеҠЁе…ій—ӯж Үеҝ—

		// дәӢд»¶еӣһи°ғеҮҪж•°
		this.onOpen = options.onOpen || function () { }
		this.onMessage = options.onMessage || function () { }
		this.onError = options.onError || function () { }
		this.onClose = options.onClose || function () { }
		this.onReconnectAttempt = options.onReconnectAttempt || function () { }
	}

	/**
	 * иҺ·еҸ–WebSocket URL
	 * еҹәдәҺйЎ№зӣ®зҡ„зҺҜеўғй…ҚзҪ®з”ҹжҲҗWebSocket URL
	 */
	getWebSocketUrl(userId) {
		// е°ҶHTTP URLиҪ¬жҚўдёәWebSocket URL
		let wsProtocol = 'ws://'
		let host = env.HOST.replace('http://', '')

		// еҰӮжһңжҳҜHTTPSпјҢеҲҷдҪҝз”ЁwssеҚҸи®®
		if (env.HOST.startsWith('https://')) {
			wsProtocol = 'wss://'
			host = env.HOST.replace('https://', '')
		}
		console.log('WebSocket URL:', `${wsProtocol}${host}/ws/${userId}`)
		return `${wsProtocol}${host}/ws/${userId}`
	}

	/**
	 * иҝһжҺҘWebSocketжңҚеҠЎеҷЁпјҲдҪҝз”Ёuni-app APIпјү
	 */
	connect() {
		// йҳІжӯўйҮҚеӨҚиҝһжҺҘ
		if (this.isConnecting || this.isConnected) {
			console.log('WebSocketе·Із»ҸеңЁиҝһжҺҘдёӯжҲ–е·ІиҝһжҺҘ')
			return
		}

		try {
			this.isConnecting = true

			// йӘҢиҜҒURLжңүж•ҲжҖ§
			if (!this.url) {
				this.url = this.getWebSocketUrl(this.userId)
				if (!this.url) {
					this.isConnecting = false
					return
				}
			}

			// еҲӣе»әWebSocketиҝһжҺҘпјҢеёҰдёҠtokenдҪңдёәиә«д»ҪйӘҢиҜҒ
			const token = getToken()
			const wsUrl = token ? `${this.url}?token=${token}` : this.url

			// дҪҝз”Ёuni-appзҡ„connectSocket API
			this.socketTask = uni.connectSocket({
				url: wsUrl,
				success: () => {
					console.log('WebSocketиҝһжҺҘиҜ·жұӮе·ІеҸ‘йҖҒ')
				},
				fail: (err) => {
					console.error('WebSocketиҝһжҺҘиҜ·жұӮеҸ‘йҖҒеӨұиҙҘ:', err)
					this.onError(err)
					this.isConnecting = false
					this.attemptReconnect()
				}
			})

			// WebSocketдәӢд»¶еӨ„зҗҶпјҲдҪҝз”Ёuni-appзҡ„дәӢд»¶зӣ‘еҗ¬пјү
			this.socketTask.onOpen(this.handleOpen.bind(this))
			this.socketTask.onMessage(this.handleMessage.bind(this))
			this.socketTask.onError(this.handleError.bind(this))
			this.socketTask.onClose(this.handleClose.bind(this))
		} catch (error) {
			console.error('WebSocketиҝһжҺҘеӨұиҙҘ:', error)
			this.onError(error)
			this.isConnecting = false
			this.attemptReconnect()
		}
	}

	/**
	 * еҸ‘йҖҒж¶ҲжҒҜпјҲдҪҝз”Ёuni-app APIпјү
	 */
	send(data) {
		if (this.isConnected && this.socketTask) {
			try {
				// еҰӮжһңиҝһжҺҘе·Іе»әз«ӢпјҢзӣҙжҺҘеҸ‘йҖҒж¶ҲжҒҜ
				const messageData = typeof data === 'string' ? data : JSON.stringify(data)
				this.socketTask.send({
					data: messageData,
					success: () => {
						console.log('ж¶ҲжҒҜеҸ‘йҖҒжҲҗеҠҹ')
					},
					fail: (err) => {
						console.error('ж¶ҲжҒҜеҸ‘йҖҒеӨұиҙҘ:', err)
						// еҸ‘йҖҒеӨұиҙҘж—¶пјҢе°Ҷж¶ҲжҒҜеҠ е…ҘйҳҹеҲ—
						this.messageQueue.push(data)
					}
				})
			} catch (error) {
				console.error('ж¶ҲжҒҜеҸ‘йҖҒеӨ„зҗҶеӨұиҙҘ:', error)
				this.messageQueue.push(data)
			}
		} else {
			// еҰӮжһңиҝһжҺҘжңӘе»әз«ӢпјҢе°Ҷж¶ҲжҒҜеҠ е…ҘйҳҹеҲ—пјҢзӯүеҫ…иҝһжҺҘе»әз«ӢеҗҺеҸ‘йҖҒ
			this.messageQueue.push(data)
			// еҰӮжһңиҝҳжІЎжңүиҝһжҺҘпјҢе°қиҜ•иҝһжҺҘ
			if (!this.isConnected && !this.isConnecting) {
				this.connect()
			}
		}
	}

	/**
	 * е…ій—ӯWebSocketиҝһжҺҘпјҲдҪҝз”Ёuni-app APIпјү
	 */
	close() {
		// и®ҫзҪ®дёәжүӢеҠЁе…ій—ӯпјҢйҒҝе…Қи§ҰеҸ‘йҮҚиҝһ
		this.isManualClose = true

		// йҮҚзҪ®зҠ¶жҖҒ
		this.isConnected = false
		this.isConnecting = false

		// жё…йҷӨйҮҚиҝһе®ҡж—¶еҷЁ
		if (this.reconnectTimer) {
			clearTimeout(this.reconnectTimer)
			this.reconnectTimer = null
		}

		// е…ій—ӯиҝһжҺҘ
		if (this.socketTask) {
			try {
				this.socketTask.close()
			} catch (error) {
				console.error('WebSocketе…ій—ӯеӨұиҙҘ:', error)
			}
			this.socketTask = null
		}
	}

	/**
	 * еӨ„зҗҶиҝһжҺҘжү“ејҖдәӢд»¶
	 */
	handleOpen(event) {
		console.log('WebSocketиҝһжҺҘе·Іжү“ејҖ')
		this.isConnected = true
		this.isConnecting = false
		this.reconnectAttempts = 0
		this.onOpen(event)

		// еҸ‘йҖҒйҳҹеҲ—дёӯзҡ„ж¶ҲжҒҜ
		this.flushMessageQueue()
	}

	/**
	 * еӨ„зҗҶжҺҘж”¶еҲ°зҡ„ж¶ҲжҒҜ
	 */
	handleMessage(event) {
		try {
			// е°қиҜ•е°Ҷж¶ҲжҒҜи§ЈжһҗдёәJSON
			const data = JSON.parse(event.data)
			this.onMessage(data)
		} catch (error) {
			// еҰӮжһңи§ЈжһҗеӨұиҙҘпјҢзӣҙжҺҘиҝ”еӣһеҺҹе§Ӣж¶ҲжҒҜ
			this.onMessage(event.data)
		}
	}

	/**
	 * еӨ„зҗҶй”ҷиҜҜдәӢд»¶
	 */
	handleError(event) {
		console.error('WebSocketй”ҷиҜҜ:', event)
		this.isConnecting = false
		this.onError(event)
	}

	/**
	 * еӨ„зҗҶиҝһжҺҘе…ій—ӯдәӢд»¶
	 */
	handleClose(event) {
		console.log('WebSocketиҝһжҺҘе·Іе…ій—ӯ', event)
		this.isConnected = false
		this.isConnecting = false
		this.socketTask = null
		this.onClose(event)

		// еҸӘжңүеңЁйқһжүӢеҠЁе…ій—ӯзҡ„жғ…еҶөдёӢжүҚе°қиҜ•йҮҚиҝһ
		if (!this.isManualClose) {
			this.attemptReconnect()
		}
	}

	/**
	 * е°қиҜ•йҮҚж–°иҝһжҺҘ
	 */
	attemptReconnect() {
		// еҰӮжһңе·Із»ҸиҫҫеҲ°жңҖеӨ§йҮҚиҝһж¬Ўж•°пјҢеҲҷеҒңжӯўйҮҚиҝһ
		if (this.reconnectAttempts >= this.maxReconnectAttempts) {
			console.error('иҫҫеҲ°жңҖеӨ§йҮҚиҝһж¬Ўж•°пјҢеҒңжӯўйҮҚиҝһ')
			return
		}

		this.reconnectAttempts++
		const attemptMessage = `з¬¬${this.reconnectAttempts}ж¬Ўе°қиҜ•йҮҚиҝһ...`
		console.log(attemptMessage)
		this.onReconnectAttempt(attemptMessage)

		// жё…йҷӨд№ӢеүҚзҡ„йҮҚиҝһе®ҡж—¶еҷЁ
		if (this.reconnectTimer) {
			clearTimeout(this.reconnectTimer)
			this.reconnectTimer = null
		}

		// жҢҮж•°йҖҖйҒҝзӯ–з•ҘпјҢеўһеҠ йҮҚиҝһй—ҙйҡ”ж—¶й—ҙ
		const currentReconnectInterval = this.reconnectInterval * Math.pow(1.5, this.reconnectAttempts - 1)

		// и®ҫзҪ®йҮҚиҝһе®ҡж—¶еҷЁ
		this.reconnectTimer = setTimeout(() => {
			// еҶҚж¬ЎйӘҢиҜҒзҠ¶жҖҒ
			if (!this.isConnected && !this.isConnecting) {
				this.connect()
			}
		}, currentReconnectInterval)
	}

	/**
	 * еҸ‘йҖҒйҳҹеҲ—дёӯзҡ„ж¶ҲжҒҜ
	 */
	flushMessageQueue() {
		// еҲӣе»әйҳҹеҲ—еүҜжң¬пјҢйҒҝе…ҚеңЁеҸ‘йҖҒиҝҮзЁӢдёӯдҝ®ж”№еҺҹйҳҹеҲ—
		const queueCopy = [...this.messageQueue]
		this.messageQueue = []

		queueCopy.forEach(message => {
			if (this.isConnected && this.socketTask) {
				this.send(message)
			} else {
				// еҰӮжһңиҝһжҺҘеңЁеҸ‘йҖҒиҝҮзЁӢдёӯж–ӯејҖпјҢе°Ҷж¶ҲжҒҜж”ҫеӣһйҳҹеҲ—
				this.messageQueue.push(message)
			}
		})
	}

	/**
	 * иҺ·еҸ–иҝһжҺҘзҠ¶жҖҒ
	 */
	getConnectionStatus() {
		return {
			isConnected: this.isConnected,
			isConnecting: this.isConnecting,
			reconnectAttempts: this.reconnectAttempts,
			maxReconnectAttempts: this.maxReconnectAttempts
		}
	}

	/**
	 * йҮҚж–°еҲқе§ӢеҢ–иҝһжҺҘ
	 * з”ЁдәҺйңҖиҰҒе®Ңе…ЁйҮҚзҪ®иҝһжҺҘзҡ„еңәжҷҜ
	 */
	reinitialize() {
		this.close()
		// йҮҚзҪ®жүӢеҠЁе…ій—ӯж Үеҝ—пјҢд»ҘдҫҝйҮҚж–°иҝһжҺҘ
		this.isManualClose = false
		this.reconnectAttempts = 0
		this.messageQueue = []
		this.url = this.getWebSocketUrl(this.userId)
		this.connect()
	}

	/**
	 * и®ҫзҪ®дәӢд»¶еӣһи°ғеҮҪж•°
	 */
	on(event, callback) {
		switch (event) {
			case 'open':
				this.onOpen = callback
				break
			case 'message':
				this.onMessage = callback
				break
			case 'error':
				this.onError = callback
				break
			case 'close':
				this.onClose = callback
				break
			case 'reconnectAttempt':
				this.onReconnectAttempt = callback
				break
			default:
				console.warn(`жңӘзҹҘдәӢд»¶зұ»еһӢ: ${event}`)
		}
	}
}

export default WebSocketClient